import { hasPermissionCode } from '../utils/erpPermissionCode';

export { hasPermissionCode };

export type PeriodJobPermissionResource =
  | 'period-allocation'
  | 'period-closing'
  | 'tools-allocation'
  | 'cost-calculation'
  | 'carry-over'
  | 'period-close-final'
  | 'depreciation';

function prefix(resource: PeriodJobPermissionResource): string {
  return `erp-finance:${resource}`;
}

/** Period job pages (`PeriodActionPanel`) — `erp-form-toolbar-permissions.md` § Tính toán. */
export function usePeriodJobPermissions(resource: PeriodJobPermissionResource) {
  const p = prefix(resource);
  return {
    canRead: hasPermissionCode(`${p}:read`),
    canRun: hasPermissionCode(`${p}:run`),
    canPost: hasPermissionCode(`${p}:post`),
  };
}
